@@ -2,112 +2,70 @@
   "$schema": "https://json-schema.org/draft/2020-12/schema",
   "$id": "https://github.com/Dicklesworthstone/doodlestein_self_releaser/schemas/fallback-details.json",
   "title": "DSR Fallback Details",
